var appealSum = function(s) {
    const last = new Map();
    let total = 0;
    let cur = 0;
    for (let i = 0; i < s.length; i++) {
        const ch = s[i];
        const prev = last.has(ch) ? last.get(ch) : -1;
        cur += i - prev;
        last.set(ch, i);
        total += cur;
    }
    return total;
};
